  uint16_t n_endpoints;
  uint16_t n_data_relocs;
  uint16_t n_control_relocs;
  uint16_t n_slotmaps;
  uint16_t n_projections;
  uint16_t n_dependencies;
  uint16_t flags;
  uint16_t physical_abi;
  uint16_t reserved;
  uint64_t pattern_key;
  SponFactSig selector_sig;
  SponFactSig required_sig;
  SponFactSig checked_sig;
  SponFactSig produced_sig;
  SponFactSig killed_sig;
} SponStencilDesc;

uint32_t spon_bank_stencil_count(void);
uint32_t spon_bank_pattern_count(void);
const SponStencilDesc *spon_get_stencil(SponStencilId id);
const unsigned char *spon_stencil_data(SponStencilId id);
const SponDataReloc *spon_stencil_data_relocs(SponStencilId id, uint32_t *out_n);
const SponControlReloc *spon_stencil_control_relocs(SponStencilId id, uint32_t *out_n);
const SponStencilChoice *spon_select_flow_flags_slots(const uint32_t *bc, uint32_t start, uint32_t end,
                                                     SponFactSig entry_sig, SponFactSig observed_sig,
                                                     uint16_t required_stencil_flags,
                                                     const SponSlotMapEntry *actual_slots,
                                                     uint32_t n_actual_slots,
                                                     uint32_t *out_n);
]]

local function assert_eq(a, b, msg) if a ~= b then error((msg or "assert_eq failed") .. ": " .. tostring(a) .. " ~= " .. tostring(b), 2) end end
local function assert_true(x, msg) if not x then error(msg or "assert_true failed", 2) end end

local bank_path = "experiments/lua_interpreter_vm/spongejit/build/sponbank/libsponbank.so"
do
  local f = io.open(bank_path, "rb")
  assert_true(f ~= nil, "missing generated L1 bank: run cd experiments/lua_interpreter_vm/spongejit && make stencils && make bank")
  if f then f:close() end
end

local bank = ffi.load(bank_path)
assert_true(bank.spon_bank_stencil_count() > 0, "empty stencil bank")
assert_true(bank.spon_bank_pattern_count() > 0, "empty pattern bank")

local function bytes_to_hex(p, n)
  local out = {}
  for i = 0, n - 1 do out[#out + 1] = string.format("%02x", tonumber(p[i])) end
  return table.concat(out)
end

local function c_data_relocs(id)
  local n = ffi.new("uint32_t[1]")
  local p = bank.spon_stencil_data_relocs(id, n)
  local out = {}
  for i = 0, tonumber(n[0]) - 1 do
    out[#out + 1] = {
      code_offset = tonumber(p[i].code_offset),
      reloc_kind = tonumber(p[i].reloc_kind),
      role_kind = tonumber(p[i].role_kind),
      op_idx = tonumber(p[i].op_idx),
      role_arg = tonumber(p[i].role_arg),
      addend = tonumber(p[i].addend),
    }
  end
  return out
end

local function c_control_relocs(id)
  local n = ffi.new("uint32_t[1]")
  local p = bank.spon_stencil_control_relocs(id, n)
  local out = {}
  for i = 0, tonumber(n[0]) - 1 do
    out[#out + 1] = {
      code_offset = tonumber(p[i].code_offset),
      reloc_kind = tonumber(p[i].reloc_kind),
      edge_kind = tonumber(p[i].edge_kind),
      endpoint_index = tonumber(p[i].endpoint_index),
      target_delta = tonumber(p[i].target_delta),
    }
  end
  return out
end

local function from_bank(id)
  local d = bank.spon_get_stencil(id)
  assert_true(d ~= nil, "missing stencil descriptor " .. tostring(id))
  assert_true(bit.band(tonumber(d.flags), 2) ~= 0, "selected stencil is not native: " .. tostring(id))
  assert_true(tonumber(d.size) > 0, "selected stencil has no native bytes: " .. tostring(id))
  local data = bank.spon_stencil_data(id)
  assert_true(data ~= nil, "spon_stencil_data returned NULL: " .. tostring(id))
  return {
    stencil_id = tonumber(d.stencil_id),
    executable = true,
    code_size = tonumber(d.size),
    code_hex = bytes_to_hex(data, tonumber(d.size)),
    data_relocs = c_data_relocs(id),
    control_relocs = c_control_relocs(id),
  }
end

local function has_edge(st, edge_kind)
  for _, cr in ipairs(st.control_relocs or {}) do if cr.edge_kind == edge_kind then return true end end
  return false
end

local FIELD_KIND = { a = 1, b = 2, c = 3, dest = 4, aux = 5 }

local function actual_slot_entries(ops)
  local xs = {}
  for pc, op in ipairs(ops or {}) do
    for field, kind in pairs(FIELD_KIND) do
      if op[field] ~= nil and tonumber(op[field]) then
        xs[#xs + 1] = { op_idx = pc - 1, logical_slot = tonumber(op[field]), field_kind = kind }
      end
    end
  end
  local arr = ffi.new("SponSlotMapEntry[?]", #xs)
  for i, x in ipairs(xs) do
    arr[i - 1].op_idx = x.op_idx
    arr[i - 1].logical_slot = x.logical_slot
    arr[i - 1].field_kind = x.field_kind
  end
  return arr, #xs
end

local function select_entries(ops, entry_sig, observed_sig)
  local bc = ffi.new("uint32_t[?]", #ops)
  for i, op in ipairs(ops) do bc[i - 1] = assert(Constants.Op[op.op], "unknown opcode " .. tostring(op.op)) end
  local slots, nslots = actual_slot_entries(ops)
  local out_n = ffi.new("uint32_t[1]")
  local choices = bank.spon_select_flow_flags_slots(bc, 0, #ops, entry_sig or 0, observed_sig or 0, 2, slots, nslots, out_n)
  local n = tonumber(out_n[0])
  assert_true(n > 0, "selector returned no choices")
  local entries = {}
  local pc = 0
  for i = 0, n - 1 do
    local ch = choices[i]
    assert_eq(tonumber(ch.pc_start), pc, "non-contiguous selector choice")
    pc = tonumber(ch.pc_end)
    local st = from_bank(tonumber(ch.stencil_id))
    local slice = {}
    for j = tonumber(ch.pc_start) + 1, tonumber(ch.pc_end) do slice[#slice + 1] = ops[j] end
    entries[#entries + 1] = { stencil = st, ops = slice }
  end
  assert_eq(pc, #ops, "selector did not cover full span")
  return entries
end

local function run_image(img, setup, check)
  local mem, n = assert(Materialize.alloc_executable(img.bytes))
  local fn = ffi.cast("void (*)(SponExecCtx *)", mem)
  local stack = ffi.new("SponTValueABI[8]")
  local k = ffi.new("SponTValueABI[8]")
  local ctx = ffi.new("SponExecCtx")
  ctx.stack = stack
  ctx.k = k
  setup(ctx, stack, k)
  fn(ctx)
  check(ctx, stack, k)
  Materialize.free_executable(mem, n)
end

-- End-to-end generated bank path:
-- C selector -> SponStencilChoice[] -> C descriptors/bytes/relocs -> Lua CLP
-- materializer -> mmap -> execute linked image.
do
  local ops = {
    { op = "ADDI", a = 0, b = 0, c = 1 },
    { op = "ADDI", a = 0, b = 0, c = 2 },
    { op = "ADDI", a = 0, b = 0, c = 3 },
    { op = "ADDI", a = 0, b = 0, c = 4 },
    { op = "ADDI", a = 0, b = 0, c = 5 },
  }
  local i64_r0 = 1
  local entries = select_entries(ops, i64_r0, i64_r0)
  assert_true(#entries >= 2, "five-op span should require at least two max-arity choices")
  assert_true(has_edge(entries[1].stencil, 1), "first bank stencil missing fallthrough edge")
  assert_true(has_edge(entries[1].stencil, 2), "first bank stencil missing guard edge")
  local img = Materialize.materialize(entries)
  assert_true(img.ok and img.code_size > 0, "bank materialization failed")

  run_image(img,
    function(ctx, stack)
      stack[0].value_ = 0
      stack[0].tt_ = 3 -- LUA_VNUMINT
      ctx.exit_kind = 99
    end,
    function(ctx, stack)
      assert_eq(tonumber(ctx.exit_kind), 0, "bank-linked ADDI exit")
      assert_eq(tonumber(stack[0].value_), 15, "bank-linked ADDI result")
      assert_eq(tonumber(stack[0].tt_), 3, "bank-linked ADDI tag")
    end)

  run_image(img,
    function(ctx, stack)
      stack[0].value_ = 0
      stack[0].tt_ = 0
      ctx.exit_kind = 99
    end,
    function(ctx, stack)
      assert_eq(tonumber(ctx.exit_kind), 1, "bank-linked guard exit")
      assert_eq(tonumber(stack[0].value_), 0, "guard failure must not run linked span")
    end)
end

print("ok - SpongeJIT generated bank selects and materializes native span")
